public:
    unordered_map<string, int> count;
    unordered_map<int, set<string>> keys;
    int minCount = 0, maxCount = 0;

    AllOne() {

    }

    void inc(string key) {
        if (count.find(key) == count.end()) {
            count[key] = 1;
            keys[1].insert(key);
            if (minCount == 0) minCount = 1;
            maxCount = max(maxCount, 1);
        } else {
            int oldCount = count[key];
            count[key]++;
            keys[oldCount].erase(key);
            if (keys[oldCount].empty()) keys.erase(oldCount);
            keys[count[key]].insert(key);
            if (oldCount == minCount && keys[minCount].empty()) minCount++;
            maxCount = max(maxCount, count[key]);
        }
    }

    void dec(string key) {
        int oldCount = count[key];
        count[key]--;
        keys[oldCount].erase(key);
        if (keys[oldCount].empty()) keys.erase(oldCount);
        if (count[key] > 0) {
            keys[count[key]].insert(key);
            if (count[key] < minCount) minCount = count[key];
        } else {
            count.erase(key);
            if (minCount == oldCount && keys.find(minCount) == keys.end()) minCount = keys.begin()->first;
        }
        if (maxCount == oldCount && keys.find(maxCount) == keys.end()) {
            if (!keys.empty()) maxCount = keys.rbegin()->first;
            else maxCount = 0;
        }
    }

    string getMaxKey() {
        if (maxCount == 0) return "";
        return *keys[maxCount].begin();
    }

    string getMinKey() {
        if (minCount == 0) return "";
        return *keys[minCount].begin();
    }
};

